div.p:
is_alive(slot):
entry = identities[slot]
// Check 1: Never used
if entry.pid == 0:
return false
// Check 2: Process exists?
if kill(entry.pid, 0) fails with ESRCH:
return false  // Process gone
// Check 3: Generation match?
// (detects PID reuse)
if entry.generation != expected_gen:
return false  // Stale registration
// Check 4: Heartbeat fresh?
age = now() - entry.last_heartbeat_ns
if age > heartbeat_timeout:
return false  // Timed out
// Check 5: State not DEAD
if entry.state == DEAD:
return false
return true
